#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int **edges = (int **)malloc(M * sizeof(int *));
        for (int i = 0; i < M; i++) {
            edges[i] = (int *)malloc(2 * sizeof(int));
            scanf("%d %d", &edges[i][0], &edges[i][1]);
        }
        // Process the graph
        int L = 2;
        int *values = (int *)malloc(N * sizeof(int));
        values[0] = 12;
        for (int i = 1; i < N; i++) {
            values[i] = values[i - 1] + 1;
        }
        int valid = 1;
        for (int i = 0; i < M; i++) {
            int u = edges[i][0] - 1;
            int v = edges[i][1] - 1;
            if (abs(values[u] - values[v]) < L / 2) {
                valid = 0;
                break;
            }
        }
        if (valid) {
            printf("Yes\n");
            printf("%d", L);
            for (int i = 0; i < N; i++) {
                printf(" %d", values[i]);
            }
            printf("\n");
        } else {
            printf("No\n");
        }
        free(values);
        for (int i = 0; i < M; i++) {
            free(edges[i]);
        }
        free(edges);
    }
    return 0;
}

