let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(Number);
}

let T = nextInt();
while (T-- > 0) {
    let [N, M] = nextInts();
    let edges = [];
    for (let i = 0; i < M; i++) {
        edges.push(nextInts());
    }
    // Process the graph
